    uint32_t usedNumBlocks = (rowLength < MAX_BLOCK) ? rowLength : MAX_BLOCK;
    context->SetBlockDim(usedNumBlocks);

    uint32_t coreRowNum = rowLength / usedNumBlocks;
    uint32_t tailRow = rowLength % usedNumBlocks;
